using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class DashboardTraining : TrainingContentBase
{
    public DashboardTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Overview",
            Slug = "dashboard-overview",
            Summary = "What the Dashboard shows, how widgets work, and how to customize your layout for daily productivity.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","widgets","home"]""",
            ContentJson = """{"body":"## Dashboard Overview\n\nThe Dashboard is your home screen — the first thing you see after logging in. It gives you an at-a-glance summary of your day: tasks due, timers running, orders in progress, and planning cycle status. Everything is organized into draggable widgets that you can rearrange to match your workflow.\n\n### Widget-Based Layout\n\nThe Dashboard uses a grid layout powered by gridstack. Each piece of information lives in its own widget card. You can drag widgets to rearrange them, and your layout is saved to your user preferences so it persists across sessions and devices.\n\n### Core Widgets\n\n**Today's Tasks:** Shows your assigned jobs sorted by due date. Overdue jobs are highlighted so you can see what needs immediate attention. Click any job to open its detail dialog.\n\n**Active Timers:** If you have a running timer, this widget shows the elapsed time, a stop button, and a link to the job you're working on. When no timer is running, the widget shows a prompt to start one.\n\n**Open Orders by Stage:** A summary of open orders grouped by stage — Quote, Production, QC, and Shipped counts. Gives you a quick sense of the pipeline without leaving the dashboard.\n\n**Cycle Progress:** Shows your current planning cycle's completion percentage. The progress bar turns yellow when you're behind schedule, helping you prioritize.\n\n**Mini Calendar:** A small calendar widget highlighting dates with due items. Click a date to see what's due.\n\n**KPI Chips:** Compact metric displays showing key numbers (jobs completed this week, hours logged, etc.).\n\n### Getting Started Banner\n\nNew users see a Getting Started banner that tracks onboarding progress — setting up your profile, completing compliance forms, reviewing training modules. The banner disappears once all onboarding steps are complete.\n\n### Profile Completeness\n\nFor new users, a Profile Completeness widget shows which items are still missing: contact information, emergency contacts, compliance forms, etc. This helps ensure your account is fully set up.\n\n### Loading and Performance\n\nThe Dashboard loads with a global loading overlay (LoadingService) because it fetches data from multiple endpoints simultaneously. Once all widgets have their data, the overlay clears and you see the full dashboard at once — no partial loading or flickering.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard — Guided Tour",
            Slug = "dashboard-walkthrough",
            Summary = "A guided tour of the Dashboard: widgets, task list, timers, order summary, cycle progress, and layout customization.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Tour Dashboard","steps":[{"element":".dashboard-content","popover":{"title":"Dashboard Content Area","description":"Your dashboard is built from draggable widgets. Grab any widget by its header and drag it to a new position. Your layout is saved automatically to your user preferences — it'll look the same next time you log in, even from a different device.","side":"top"}},{"element":".dashboard-kpis","popover":{"title":"KPI Overview","description":"Key performance indicators displayed as compact chips at the top of the dashboard. Shows metrics like jobs completed, hours logged, and items shipped for a quick status check.","side":"bottom"}},{"element":"app-page-header","popover":{"title":"Page Header & Controls","description":"The dashboard header with edit and ambient mode controls. Use these to customize your widget layout or toggle the ambient dashboard display.","side":"bottom"}},{"element":"app-dashboard-widget","popover":{"title":"Dashboard Widget","description":"Each widget in the grid shows a different piece of information — tasks, timers, orders, calendar, or cycle progress. Widget order is customizable by dragging. Widgets update in real time as work moves through the board.","side":"right"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Field Reference",
            Slug = "dashboard-field-reference",
            Summary = "Complete reference for every widget, indicator, action, and behavior on the Dashboard.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","reference"]""",
            ContentJson = """{"title":"Dashboard Field Reference","groups":[{"heading":"Today's Tasks Widget","items":[{"label":"Job List","value":"Shows your assigned jobs sorted by due date (earliest first). Each row displays the job title, due date, priority indicator, and current stage."},{"label":"Overdue Highlight","value":"Jobs past their due date are highlighted with a red/error color so they stand out from upcoming tasks."},{"label":"Click Action","value":"Click any job row to open the job detail dialog. From there you can view subtasks, files, activity, and take actions."},{"label":"Empty State","value":"When you have no assigned tasks, the widget shows an empty state message with an icon."}]},{"heading":"Active Timers Widget","items":[{"label":"Running Timer","value":"Displays the elapsed time (hours:minutes:seconds) updating in real time. Shows the job name as a clickable link."},{"label":"Stop Button","value":"Stops the running timer and logs the time entry. Only visible when a timer is active."},{"label":"Job Name Link","value":"Click the job name to open the job detail dialog without stopping the timer."},{"label":"No Timer State","value":"When no timer is running, the widget shows a prompt or empty state indicating you can start a timer from a job's detail view."}]},{"heading":"Open Orders by Stage Widget","items":[{"label":"Stage Counts","value":"Shows the number of open orders at each major stage: Quote, Production, QC, and Shipped."},{"label":"Visual Layout","value":"Displayed as a horizontal summary with counts per stage, giving a pipeline overview."},{"label":"Click Action","value":"Stages may be clickable to navigate to the relevant filtered view (e.g., Kanban board filtered to that stage)."}]},{"heading":"Cycle Progress Widget","items":[{"label":"Progress Bar","value":"Horizontal bar showing percentage of current planning cycle items completed."},{"label":"Yellow Warning","value":"The bar turns yellow when completion is behind schedule relative to elapsed cycle time."},{"label":"Percentage Label","value":"Shows the exact completion percentage as a number."},{"label":"Click Action","value":"Click to navigate to the Planning page for the full cycle detail."}]},{"heading":"Profile Completeness Widget (New Users)","items":[{"label":"Missing Items List","value":"Shows which profile items are still incomplete: contact information, emergency contacts, compliance forms, training modules."},{"label":"Progress Indicator","value":"Visual progress showing how much of the profile setup is done."},{"label":"Visibility","value":"Only shown to new users who haven't completed their profile. Disappears once all items are filled in."}]},{"heading":"Getting Started Banner","items":[{"label":"Onboarding Checklist","value":"Tracks onboarding progress: profile setup, compliance forms, training completion, first job view."},{"label":"Dismiss Behavior","value":"The banner disappears automatically when all onboarding steps are complete. Cannot be manually dismissed while steps remain."}]},{"heading":"Mini Calendar Widget","items":[{"label":"Calendar Grid","value":"Small monthly calendar (mat-calendar) showing the current month with navigation arrows."},{"label":"Highlighted Dates","value":"Dates with due items (jobs, orders, events) are visually highlighted with a dot or color."},{"label":"Date Click","value":"Click a highlighted date to see the items due on that day."}]},{"heading":"KPI Chips","items":[{"label":"Metrics Displayed","value":"Compact chips showing key performance indicators: jobs completed this week, hours logged, items shipped, etc."},{"label":"Visual Style","value":"Small colored chips using the KpiChipComponent. Each shows a label and value."}]},{"heading":"Layout and Preferences","items":[{"label":"Drag to Rearrange","value":"Grab any widget by its header and drag to reposition. The grid snaps widgets into place."},{"label":"Layout Persistence","value":"Your widget arrangement is saved to user preferences (localStorage + API). Restored on login from any device."},{"label":"Grid System","value":"Powered by gridstack. Widgets have default sizes but can be rearranged freely within the grid."}]},{"heading":"Loading Behavior","items":[{"label":"Initial Load","value":"Dashboard uses LoadingService global overlay while fetching data from multiple endpoints. The overlay clears once all widget data is ready."},{"label":"No Partial Loading","value":"All widgets load together behind the overlay — you see the complete dashboard at once, no flickering or progressive rendering."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
