            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["dashboard","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"db1","text":"You log in to QB Engineer and see a loading overlay before the Dashboard appears. Why does the Dashboard load this way?","options":[{"id":"a","text":"The Dashboard is slow because it renders 3D graphics"},{"id":"b","text":"It uses a global loading overlay because it fetches data from multiple endpoints simultaneously — all widgets load together behind the overlay","isCorrect":true},{"id":"c","text":"Each widget loads independently with its own spinner"},{"id":"d","text":"The loading overlay is a bug — the Dashboard should load instantly from cache"}],"explanation":"The Dashboard uses LoadingService (global overlay) because it fetches data from multiple API endpoints at once. The overlay clears when all data is ready, so you see the complete dashboard without partial loading or flickering."},{"id":"db2","text":"You see a job highlighted in red in the Today's Tasks widget. What does this mean?","options":[{"id":"a","text":"The job has been flagged as high priority by a manager"},{"id":"b","text":"The job's due date has passed — it's overdue","isCorrect":true},{"id":"c","text":"The job is blocked by a hold and cannot proceed"},{"id":"d","text":"The job was recently assigned to you and hasn't been viewed yet"}],"explanation":"Overdue jobs (past their due date) are highlighted with red/error coloring in the Today's Tasks widget so they stand out from upcoming tasks and get immediate attention."},{"id":"db3","text":"You rearrange your Dashboard widgets by dragging them to new positions. What happens to your layout?","options":[{"id":"a","text":"It resets to default when you refresh the page"},{"id":"b","text":"It's saved to your user preferences and persists across sessions and devices","isCorrect":true},{"id":"c","text":"It's only saved in the current browser tab"},{"id":"d","text":"You need to click a Save Layout button to persist changes"}],"explanation":"Widget positions are saved automatically to user preferences (localStorage + API). Your layout is restored when you log in from any device — no manual save needed."},{"id":"db4","text":"The Cycle Progress bar has turned yellow. What does this indicate?","options":[{"id":"a","text":"The planning cycle has been paused by an admin"},{"id":"b","text":"You're ahead of schedule and have extra capacity"},{"id":"c","text":"You're behind schedule — completion percentage is lower than expected for the elapsed time","isCorrect":true},{"id":"d","text":"The cycle ends today and you should start planning the next one"}],"explanation":"The progress bar turns yellow when your completion rate is behind where it should be given how much of the cycle has elapsed. This is a visual cue to prioritize cycle items."},{"id":"db5","text":"You want to stop a running timer from the Dashboard. How?","options":[{"id":"a","text":"Navigate to Time Tracking and click the stop button there"},{"id":"b","text":"Click the stop button in the Active Timers widget on the Dashboard","isCorrect":true},{"id":"c","text":"Close the browser — the timer auto-stops after 30 minutes of inactivity"},{"id":"d","text":"You can only stop timers from the job's detail panel"}],"explanation":"The Active Timers widget shows your running timer with a stop button right on the Dashboard. Click it to stop the timer and log the time entry without navigating away."},{"id":"db6","text":"You click a job in the Today's Tasks widget. What happens?","options":[{"id":"a","text":"The job's Kanban card is highlighted on the board"},{"id":"b","text":"The job detail dialog opens, showing subtasks, files, activity log, and available actions","isCorrect":true},{"id":"c","text":"A summary tooltip appears with the job title and due date"},{"id":"d","text":"You're navigated to the Backlog page with that job selected"}],"explanation":"Clicking a job in Today's Tasks opens the full job detail dialog. From there you can view and manage subtasks, files, activity history, and take actions like starting a timer or updating status."},{"id":"db7","text":"A new employee logs in and sees a 'Getting Started' banner on their Dashboard. When does this banner disappear?","options":[{"id":"a","text":"After 7 days, regardless of progress"},{"id":"b","text":"When the employee clicks 'Dismiss' on the banner"},{"id":"c","text":"When all onboarding steps are complete — profile, compliance forms, training","isCorrect":true},{"id":"d","text":"It never disappears — it transforms into a regular widget"}],"explanation":"The Getting Started banner tracks onboarding progress and disappears automatically once all steps are complete. It cannot be manually dismissed while onboarding steps remain."},{"id":"db8","text":"You see highlighted dates on the Mini Calendar widget. What do they represent?","options":[{"id":"a","text":"Company holidays and days off"},{"id":"b","text":"Dates with due items — jobs, orders, or events","isCorrect":true},{"id":"c","text":"Days you were clocked in last month"},{"id":"d","text":"Planning cycle start and end dates only"}],"explanation":"The Mini Calendar highlights dates that have due items (jobs, orders, events). Click a highlighted date to see what's due on that day."},{"id":"db9","text":"The Profile Completeness widget shows 'Emergency Contact' as a missing item. What should you do?","options":[{"id":"a","text":"Ask your manager to fill it in for you in Admin"},{"id":"b","text":"Go to your Account settings and add your emergency contact information","isCorrect":true},{"id":"c","text":"Ignore it — emergency contacts are optional"},{"id":"d","text":"Submit a support ticket to have it added"}],"explanation":"The Profile Completeness widget shows items you need to fill in yourself. Navigate to your Account settings to add the missing emergency contact. The widget updates once the information is saved."},{"id":"db10","text":"How are jobs sorted in the Today's Tasks widget?","options":[{"id":"a","text":"Alphabetically by job title"},{"id":"b","text":"By priority (highest first), then by due date"},{"id":"c","text":"By due date — earliest due date first","isCorrect":true},{"id":"d","text":"By creation date — newest first"}],"explanation":"Today's Tasks sorts jobs by due date with the earliest (most urgent) at the top. Overdue jobs appear first since their due date has already passed."},{"id":"db11","text":"You want to see how many orders are currently in production. Where do you look on the Dashboard?","options":[{"id":"a","text":"The KPI chips at the top of the page"},{"id":"b","text":"The Open Orders by Stage widget — it shows counts for Quote, Production, QC, and Shipped","isCorrect":true},{"id":"c","text":"The Today's Tasks widget — count the items manually"},{"id":"d","text":"The Cycle Progress widget — it breaks down by stage"}],"explanation":"The Open Orders by Stage widget shows a pipeline summary with counts at each major stage: Quote, Production, QC, and Shipped. Look at the Production count for your answer."},{"id":"db12","text":"The Active Timers widget is empty and shows no timer. What does this mean?","options":[{"id":"a","text":"The timer feature is disabled for your account"},{"id":"b","text":"You don't have any assigned jobs"},{"id":"c","text":"No timer is currently running — you can start one from a job's detail view","isCorrect":true},{"id":"d","text":"Your last timer was automatically stopped due to inactivity"}],"explanation":"When no timer is running, the Active Timers widget shows an empty/prompt state. To start a timer, open a job's detail dialog (from Today's Tasks, Kanban, or Backlog) and use the timer controls there."}]}"""
        });

        Log.Information("Seeded Dashboard training modules");
    }
